1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const BLOCK_OF_3_PRICE = 60;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	export function processScenario(scenario: any): any {
22	  const results: any[] = [];
23	  let quoteCount = 0;
24	  for (const step of scenario.steps) {
25	    let basePremium = 0;
26	    const typeCounts: Record<string, number> = {};
27	    for (const item of step.items) {
28	      typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
29	    }
30	    for (const [type, count] of Object.entries(typeCounts)) {
31	      const isComponentType = COMPONENT_TYPES.has(type);
32	      const formsBlockOf3 = count === 3 && isComponentType;
33	      if (formsBlockOf3) {
34	        basePremium += BLOCK_OF_3_PRICE;
35	      } else {
36	        basePremium += count * BASE_PREMIUM[type];
37	      }
38	    }
39	    let curseSurcharge = 0;
40	    let highEnchantmentSurcharge = 0;
41	    for (const item of step.items) {
42	      if (item.cursed) {
43	        curseSurcharge += BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
44	      }
45	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
46	        highEnchantmentSurcharge += BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
47	      }
48	    }
49	    let loyaltyDiscount = 0;
50	    if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
51	      loyaltyDiscount = basePremium * LOYALTY_DISCOUNT_RATE;
52	    }
53	    const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
54	    let followUpDiscount = 0;
55	    if (quoteCount > 0) {
56	      followUpDiscount = basePremium * FOLLOW_UP_DISCOUNT_RATE;
57	    }
58	    const premium = basePremium + curseSurcharge + highEnchantmentSurcharge - loyaltyDiscount + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE;
59	    results.push({ premium });
60	    quoteCount++;
61	  }
62	  return { results };
63	}
